import { useState } from 'react';
import { Routes, Route } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import ChatWindow from '../components/User/Chat/ChatWindow';
import StatusFeed from '../components/User/Status/StatusFeed';
import ProfilePage from '../components/User/Profile/ProfilePage';
import GoSpace from '../components/User/Friends/GoSpace';
import ReferralDashboard from '../components/User/Referral/ReferralDashboard';

export default function MainApp() {
  const { user, logoutUser } = useAuth();
  const [activeTab, setActiveTab] = useState('chats');
  const [activeContact, setActiveContact] = useState(null);

  const tabs = [
    { id: 'chats', label: '💬', title: 'Chats' },
    { id: 'status', label: '📡', title: 'Status' },
    { id: 'gospace', label: '👥', title: 'GoSpace' },
    { id: 'referrals', label: '🎁', title: 'Referrals' },
    { id: 'profile', label: '👤', title: 'Profile' },
  ];

  if (user?.role === 'admin' || user?.role === 'moderator') {
    tabs.push({ id: 'admin', label: '🛡️', title: 'Admin' });
  }

  return (
    <div className="main-app">
      {/* Sidebar navigation */}
      <div className="app-sidebar-nav">
        <div className="app-logo">N<span>C</span></div>
        {tabs.map(tab => (
          <button
            key={tab.id}
            className={`nav-tab ${activeTab === tab.id ? 'active' : ''}`}
            onClick={() => setActiveTab(tab.id)}
            title={tab.title}
          >
            {tab.label}
          </button>
        ))}
        <div className="nav-spacer" />
        <button className="nav-tab logout" onClick={logoutUser} title="Logout">🚪</button>
      </div>

      {/* Content area */}
      <div className="app-content">
        {activeTab === 'chats' && (
          <div className="chats-layout">
            <div className="contacts-sidebar">
              <div className="contacts-header"><h3>Messages</h3></div>
              {/* Contact list would be populated from API */}
              <div className="contact-list-placeholder">
                <p>Your conversations will appear here</p>
              </div>
            </div>
            <ChatWindow contact={activeContact} />
          </div>
        )}
        {activeTab === 'status' && <StatusFeed />}
        {activeTab === 'gospace' && <GoSpace />}
        {activeTab === 'referrals' && <ReferralDashboard />}
        {activeTab === 'profile' && <ProfilePage />}
        {activeTab === 'admin' && <div style={{ padding: '2rem' }}><a href="/admin">Open Admin Panel →</a></div>}
      </div>
    </div>
  );
}
